$command = Get-Command Get-Tpm -ErrorAction SilentlyContinue
if ($null -eq $command) {
    [pscustomobject]@{
        command_available = $false
        success = $false
        error = "Get-Tpm unavailable"
    } | ConvertTo-Json -Compress
    exit 0
}
try {
    $value = Get-Tpm
    [pscustomobject]@{
        command_available = $true
        success = $true
        tpm_present = [bool]$value.TpmPresent
        tpm_ready = [bool]$value.TpmReady
        tpm_enabled = [bool]$value.TpmEnabled
        tpm_activated = [bool]$value.TpmActivated
        tpm_owned = [bool]$value.TpmOwned
        restart_pending = [bool]$value.RestartPending
        manufacturer_id = [string]$value.ManufacturerIdTxt
        manufacturer_version = [string]$value.ManufacturerVersion
        auto_provisioning = [string]$value.AutoProvisioning
    } | ConvertTo-Json -Compress
} catch {
    [pscustomobject]@{
        command_available = $true
        success = $false
        error = $_.Exception.Message
    } | ConvertTo-Json -Compress
}

try {
    $values = @(
        Get-CimInstance `
            -Namespace "root/CIMV2/Security/MicrosoftTpm" `
            -ClassName "Win32_Tpm" `
            -ErrorAction Stop |
        ForEach-Object {
            [pscustomobject]@{
                manufacturer_id = [string]$_.ManufacturerId
                manufacturer_version = [string]$_.ManufacturerVersion
                spec_version = [string]$_.SpecVersion
                is_enabled_initial = [bool]$_.IsEnabled_InitialValue
                is_activated_initial = [bool]$_.IsActivated_InitialValue
                is_owned_initial = [bool]$_.IsOwned_InitialValue
            }
        }
    )
    [pscustomobject]@{
        success = $true
        count = $values.Count
        values = $values
    } | ConvertTo-Json -Depth 6 -Compress
} catch {
    [pscustomobject]@{
        success = $false
        count = 0
        values = @()
        error = $_.Exception.Message
    } | ConvertTo-Json -Depth 4 -Compress
}

$ErrorActionPreference = "Stop"
$source = @"
using System;
using System.Runtime.InteropServices;

public static class UbdbCryptoProbe
{
    [DllImport("ncrypt.dll", CharSet = CharSet.Unicode)]
    public static extern int NCryptOpenStorageProvider(
        out IntPtr phProvider,
        string pszProviderName,
        uint dwFlags
    );

    [DllImport("ncrypt.dll")]
    public static extern int NCryptFreeObject(IntPtr hObject);

    [DllImport("bcrypt.dll", CharSet = CharSet.Unicode)]
    public static extern int BCryptOpenAlgorithmProvider(
        out IntPtr phAlgorithm,
        string pszAlgId,
        string pszImplementation,
        uint dwFlags
    );

    [DllImport("bcrypt.dll")]
    public static extern int BCryptCloseAlgorithmProvider(
        IntPtr hAlgorithm,
        uint dwFlags
    );
}
"@
Add-Type -TypeDefinition $source -Language CSharp

$providers = @(
    "Microsoft Software Key Storage Provider",
    "Microsoft Platform Crypto Provider",
    "Microsoft Smart Card Key Storage Provider"
)

$providerResults = foreach ($name in $providers) {
    $handle = [IntPtr]::Zero
    $status = [UbdbCryptoProbe]::NCryptOpenStorageProvider(
        [ref]$handle,
        $name,
        0
    )
    if ($handle -ne [IntPtr]::Zero) {
        [void][UbdbCryptoProbe]::NCryptFreeObject($handle)
    }
    [pscustomobject]@{
        name = $name
        status = $status
        available = ($status -eq 0)
    }
}

$algorithms = @("ECDSA_P256", "ECDH_P256", "SHA256")
$algorithmResults = foreach ($name in $algorithms) {
    $handle = [IntPtr]::Zero
    $status = [UbdbCryptoProbe]::BCryptOpenAlgorithmProvider(
        [ref]$handle,
        $name,
        $null,
        0
    )
    if ($handle -ne [IntPtr]::Zero) {
        [void][UbdbCryptoProbe]::BCryptCloseAlgorithmProvider(
            $handle,
            0
        )
    }
    [pscustomobject]@{
        name = $name
        status = $status
        available = ($status -eq 0)
    }
}

[pscustomobject]@{
    providers = @($providerResults)
    algorithms = @($algorithmResults)
    private_key_created = $false
    private_key_opened = $false
} | ConvertTo-Json -Depth 6 -Compress
